#!/bin/bash\n# Install script for threat-mitigation-mapping skill\n\necho "Installing dependencies for threat-mitigation-mapping..."\n\n# Update package list\necho "Updating package list..."\napt-get update -y\n\n# Install Python3 if not present\nif ! command -v python3 &> /dev/null; then\n    echo "Installing python3..."\n    apt-get install -y python3 python3-pip\nelse\n    echo "Python3 already installed."\nfi\n\necho "✅ threat-mitigation-mapping dependencies installed."
